union EmployeeProvisioningState {
  string,
  ResourceProvisioningState,

  /** The resource is being provisioned */
  Provisioning: "Provisioning",

  /** The resource is being updated */
  Updating: "Updating",

  /** The resource is being deleted */
  Deleting: "Deleting",

